const h = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const token = h['x-meta-token'];
const account = h['x-meta-account'];
if (!token || !account) {
  $execution.abort({ message: 'Missing Meta credentials' });
}
const name = (body.name || '').trim();
if (!name) {
  $execution.abort({ message: 'Campaign name is required' });
}
const VALID_OBJECTIVES = ['OUTCOME_SALES','OUTCOME_TRAFFIC','OUTCOME_LEADS','OUTCOME_AWARENESS','OUTCOME_ENGAGEMENT','OUTCOME_APP_PROMOTION'];
const objective = VALID_OBJECTIVES.includes(body.objective) ? body.objective : 'OUTCOME_SALES';
const daily_budget = Math.max(100, parseInt(body.daily_budget) || 1000); // in cents
const countries = Array.isArray(body.countries) && body.countries.length ? body.countries : ['US'];
const start_time = body.start_time || new Date().toISOString();
return [{ json: { token, account, name, objective, daily_budget, countries, start_time } }];

const { token, account, name, objective, daily_budget, countries, start_time } = $input.item.json;
const GRAPH = 'https://graph.facebook.com/v19.0';

// Step 1: Create Campaign
const campaignRes = await fetch(`${GRAPH}/act_${account}/campaigns`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({
    name,
    objective,
    status: 'PAUSED',
    special_ad_categories: '[]',
    access_token: token
  }).toString()
});
const campaign = await campaignRes.json();
if (campaign.error) {
  return [{ json: { success: false, error: campaign.error.message, step: 'campaign_create' } }];
}
const campaign_id = campaign.id;

// Step 2: Create Ad Set
const targeting = JSON.stringify({
  geo_locations: { countries },
  age_min: 18,
  age_max: 65,
  publisher_platforms: ['facebook','instagram']
});
const adSetBody = new URLSearchParams({
  name: `${name} - Ad Set`,
  campaign_id,
  daily_budget: String(daily_budget),
  billing_event: 'IMPRESSIONS',
  optimization_goal: objective === 'OUTCOME_SALES' ? 'OFFSITE_CONVERSIONS' : objective === 'OUTCOME_TRAFFIC' ? 'LINK_CLICKS' : 'REACH',
  targeting,
  status: 'PAUSED',
  start_time,
  access_token: token
});
const adSetRes = await fetch(`${GRAPH}/act_${account}/adsets`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: adSetBody.toString()
});
const adSet = await adSetRes.json();
if (adSet.error) {
  return [{ json: { success: false, error: adSet.error.message, step: 'adset_create', campaign_id } }];
}

return [{ json: {
  success: true,
  campaign_id,
  adset_id: adSet.id,
  campaign_name: name,
  objective,
  daily_budget,
  countries,
  status: 'PAUSED',
  message: `Campaign "${name}" created successfully (paused — review and activate when ready)`
} }];
